using System.Security.Claims;using Kafo.Web.Data;using Kafo.Web.Models.Organizations;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;
namespace Kafo.Web.Areas.Portal.Controllers;[Area("Portal")]public class OrganizationEvaluationsController:Controller{private readonly ApplicationDbContext _context;public OrganizationEvaluationsController(ApplicationDbContext context)=>_context=context;[HttpGet("/Portal/Organization/Evaluations")]public async Task<IActionResult> Index(){var id=GetOrganizationId();ViewBag.Requests=await _context.OpportunityRequests.AsNoTracking().Where(x=>x.OrganizationAccountId==id).OrderByDescending(x=>x.CreatedAt).ToListAsync();return View("~/Areas/Portal/Views/OrganizationEvaluations/Index.cshtml",await _context.OrganizationEvaluations.AsNoTracking().Include(x=>x.OpportunityRequest).Where(x=>x.OrganizationAccountId==id).OrderByDescending(x=>x.CreatedAt).ToListAsync());}[HttpPost("/Portal/Organization/Evaluations")][ValidateAntiForgeryToken]public async Task<IActionResult> Create(int? opportunityRequestId,int candidateQualityRate,int serviceRate,string? notes){var id=GetOrganizationId();if(candidateQualityRate is<1 or>5||serviceRate is<1 or>5){TempData["Error"]="التقييم يجب أن يكون من 1 إلى 5.";return RedirectToAction(nameof(Index));}if(opportunityRequestId.HasValue&&!await _context.OpportunityRequests.AnyAsync(x=>x.Id==opportunityRequestId&&x.OrganizationAccountId==id))return NotFound();_context.OrganizationEvaluations.Add(new OrganizationEvaluation{OrganizationAccountId=id,OpportunityRequestId=opportunityRequestId,CandidateQualityRate=candidateQualityRate,ServiceRate=serviceRate,Notes=notes?.Trim(),CreatedAt=DateTime.Now});await _context.SaveChangesAsync();TempData["Success"]="شكرًا، تم تسجيل تقييم الخدمة.";return RedirectToAction(nameof(Index));}private int GetOrganizationId()=>int.TryParse(User.FindFirstValue("KafoOrganizationUserId"),out var id)?id:0;}
